import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { deleteStaff, getStaff, updateStaff } from "../../api/adminUserApi";
import { getAuth } from "../../utils/auth";

export default function StaffList() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);

  const { role } = getAuth();
  const isAdmin = role === "admin";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getStaff();
      setUsers(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load users");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const toggleActive = async (u) => {
    try {
      await updateStaff(u._id, { isDeleted: !u.isDeleted });
      await load();
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

const hardDelete = async (u) => {
  if (!window.confirm(`Permanently delete ${u.name}?`)) return;

  try {
    await deleteStaff(u._id);

    // instantly remove from UI without reload
    setUsers(prev => prev.filter(user => user._id !== u._id));

    alert("User deleted permanently");
  } catch (err) {
    alert(err.response?.data?.message || "Delete failed");
  }
};

  if (!isAdmin) {
    return (
      <div style={{ padding: 20 }}>
        <h2>Staff Management</h2>
        <p>Access denied</p>
      </div>
    );
  }

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Staff / Users</h2>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} disabled={loading}>
            {loading ? "Loading..." : "Refresh"}
          </button>

          <Link to="/admin/create-staff">
            <button>+ Create Staff</button>
          </Link>
        </div>
      </div>

      <table border="1" cellPadding="10" style={{ width: "100%", marginTop: 14, textAlign: "left" }}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Role</th>
            <th>Status</th>
            <th style={{ width: 260 }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u._id}>
              <td>{u.name}</td>
              <td>{u.email}</td>
              <td>{u.role}</td>
              <td>{u.isDeleted ? "Deactivated" : "Active"}</td>
              <td>
                <Link to={`/admin/staff/edit/${u._id}`}>
                  <button>Edit</button>
                </Link>

                <button style={{ marginLeft: 6 }} onClick={() => toggleActive(u)}>
                  {u.isDeleted ? "Activate" : "Deactivate"}
                </button>
                <button style={{ marginLeft: 6 }} onClick={() => hardDelete(u)}>
                    Delete
                </button>
              </td>
            </tr>
          ))}

          {users.length === 0 && !loading && (
            <tr>
              <td colSpan="5">No users found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
